import:py math;

can circle_area(radius: float) -> float {
    return math.pi * radius * radius;
}

can describe_area(radius: float) -> str {
    area: float = circle_area(radius);
    if area > 50.0 {
        return "large circle";
    } else {
        return "small circle";
    }
}

