node City {
    has name: str;
    has index: int;

    can label() -> str {
        return self.name + "#" + str(self.index);
    }
}

edge Road {
    has distance: int;
}

can nearest_city(from_index: int, distances: list[list[int]], cities: list[City]) -> str {
    best_index: int = -1;
    best_distance: int = 999999;
    row: list[int] = distances[from_index];
    for idx in range(0, len(row)) {
        if idx != from_index {
            if row[idx] < best_distance {
                best_distance = row[idx];
                best_index = idx;
            }
        }
    }
    return cities[best_index].name;
}

