can route_response(path: str) -> str {
    if path == "/" {
        return "home page";
    } elif path == "/health" {
        return "ok";
    } elif path == "/users" {
        return "user list";
    } else {
        return "not found";
    }
}

can render_requests(paths: list[str]) -> list[str] {
    responses: list[str] = [];
    for path in paths {
        responses.append(path + " -> " + route_response(path));
    }
    return responses;
}

