walker ScoreWalker {
    has threshold: int = 0;
    has accepted: list[str] = [];

    can record(name: str, score: int) {
        if score >= self.threshold {
            self.accepted.append(name);
        }
    }
}

can select_best_unvisited(distances: dict[str, int], visited: list[str]) -> str {
    best_name: str = "";
    best_distance: int = 999999;
    for name in distances {
        if !(name in visited) {
            if distances[name] < best_distance {
                best_distance = distances[name];
                best_name = name;
            }
        }
    }
    return best_name;
}

can shortest_paths(graph: dict[str, dict[str, int]], start: str) -> dict[str, int] {
    distances: dict[str, int] = {};
    visited: list[str] = [];
    for name in graph {
        distances[name] = 999999;
    }
    distances[start] = 0;
    while len(visited) < len(graph) {
        current: str = select_best_unvisited(distances, visited);
        if current == "" {
            break;
        }
        visited.append(current);
        for neighbor in graph[current] {
            candidate: int = distances[current] + graph[current][neighbor];
            if candidate < distances[neighbor] {
                distances[neighbor] = candidate;
            }
        }
    }
    return distances;
}

